#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, F;
        scanf("%d %d", &N, &F);
        int heights[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &heights[i]);
        }
        int count = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                int taller = (heights[i] > heights[j]) ? heights[i] : heights[j];
                int shorter = (heights[i] < heights[j]) ? heights[i] : heights[j];
                int bounces = 0;
                while (taller > shorter) {
                    taller /= F;
                    bounces++;
                }
                if (taller == shorter) {
                    count++;
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

